"use client";

import Image from "next/image";
import { useRef, useEffect } from "react";
import Link from "next/link";
import ManagedImage from "@/components/ui/ManagedImage";

export default function FeaturedCategories() {
  const trackRef = useRef(null);
  const animRef = useRef(null);
  const posRef = useRef(0);
  const pausedRef = useRef(false);

  const items = [
    {
      name: "Online Degrees",
      image: "data:image/png;base64,",
      link: "/top11/online-degrees",
    },
    {
      name: "VPN",
      image: "/top11/top2.png",
      link: "/top11/vpn",
    },
    {
      name: "CRM",
      image: "data:image/png;base64,",
      link: "/top11/crm",
    },
    {
      name: "VOIP",
      image: "data:image/png;base64,",
      link: "/top11/voip",
    },
    {
      name: "Web Hosting",
      image: "data:image/png;base64,",
      link: "/top11/web-hosting",
    },
    {
      name: "TV Services",
      image: "data:image/png;base64,",
      link: "/top11/tv-services",
    },
    {
      name: "Car Selling",
      image: "data:image/png;base64,",
      link: "/top11/car-selling",
    },
    {
      name: "Home Warranty",
      image: "data:image/png;base64,",
      link: "/top11/home-warranty",
    },
    {
      name: "Online Therapy",
      image: "data:image/png;base64,",
      link: "/top11/online-therapy",
    },
    // {
    //   name: "Project Management",
    //   image: "https://logo.clearbit.com/asana.com",
    //   link: "/top11/project-management",
    // },
  ];

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;

    const raf = requestAnimationFrame(() => {
      const halfWidth = track.scrollWidth / 2;
      const speed = 0.5;

      const step = () => {
        if (!pausedRef.current) {
          posRef.current += speed;

          if (posRef.current >= halfWidth) {
            posRef.current -= halfWidth;
          }

          track.style.transform = `translateX(-${posRef.current}px)`;
        }

        animRef.current = requestAnimationFrame(step);
      };

      animRef.current = requestAnimationFrame(step);
    });

    return () => {
      cancelAnimationFrame(animRef.current);
      cancelAnimationFrame(raf);
    };
  }, []);

  const list = [...items, ...items];

  return (
    <section className="section bg-white overflow-hidden py-8">
      <div
        className="relative w-full overflow-hidden"
        onMouseEnter={() => (pausedRef.current = true)}
        onMouseLeave={() => (pausedRef.current = false)}
      >
        {/* Gradient fade */}
        <div className="pointer-events-none absolute inset-y-0 left-0 w-16 z-10 bg-gradient-to-r from-white to-transparent" />
        <div className="pointer-events-none absolute inset-y-0 right-0 w-16 z-10 bg-gradient-to-l from-white to-transparent" />

        <div
          ref={trackRef}
          className="flex will-change-transform"
          style={{ width: "max-content" }}
        >
          {list.map((item, index) => (
            <Link
              key={`${item.name}-${index}`}
              href={item.link} prefetch={false}
              className="flex items-center justify-center shrink-0 
              bg-white  
              px-6 py-4 mx-3  
             transition-all duration-300"
            >
              <div className="relative w-[120px] h-[40px]">
                <ManagedImage
                  src={item.image}
                  alt={item.name}
                  fill
                  className="object-cover"
                />
              </div>
            </Link>
          ))}
        </div>
      </div>
    </section>
  );
}